  { id: '4', name: 'Portable Speaker', price: 79.99, category: 'Electronics', rating: 4.0, reviews: 2100, inStock: true },
  { id: '5', name: 'Noise Canceling Pro', price: 379.99, category: 'Electronics', rating: 4.7, reviews: 890, inStock: true },
];

// Native math helpers ‚ÄĒ replaces lodash + mathjs
function nativeMean(arr: number[]) {
  return arr.reduce((s, v) => s + v, 0) / arr.length;
}
function nativeMedian(arr: number[]) {
  const sorted = [...arr].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}
function nativeStd(arr: number[]) {
  const m = nativeMean(arr);
  return Math.sqrt(arr.reduce((s, v) => s + (v - m) ** 2, 0) / arr.length);
}
function nativeVariance(arr: number[]) {
  const m = nativeMean(arr);
  return arr.reduce((s, v) => s + (v - m) ** 2, 0) / arr.length;
}
function nativeQuantile(arr: number[], q: number) {
  const sorted = [...arr].sort((a, b) => a - b);
  const pos = q * (sorted.length - 1);
  const lo = Math.floor(pos);
  const hi = Math.ceil(pos);
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo);
}

function ComparisonTable({ products }: { products: Product[] }) {
  const sorted = useMemo(() => [...products].sort((a, b) => a.price - b.price), [products]);
  const avgPrice = useMemo(() => nativeMean(products.map(p => p.price)), [products]);
  const totalReviews = useMemo(() => products.reduce((s, p) => s + p.reviews, 0), [products]);
  const bestRated = useMemo(() => products.reduce((best, p) => p.rating > best.rating ? p : best), [products]);
  const cheapest = useMemo(() => products.reduce((best, p) => p.price < best.price ? p : best), [products]);

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
