  { id: '5', name: 'Noise Canceling Pro', price: 379.99, category: 'Electronics', rating: 4.7, reviews: 890, inStock: true },
];

function ComparisonTable({ products }: { products: Product[] }) {
  const sorted = useMemo(() => sortBy(products, ['price']), [products]);
  const avgPrice = useMemo(() => meanBy(products, 'price'), [products]);
  const totalReviews = useMemo(() => sumBy(products, 'reviews'), [products]);
  const bestRated = useMemo(() => maxBy(products, 'rating'), [products]);
  const cheapest = useMemo(() => minBy(products, 'price'), [products]);

  return (
    <div className=\"bg-white rounded-xl shadow-md p-6\">
