            <th className="px-4 py-3 text-center">Stock</th>
          </tr>
        </thead>
        <tbody>
          {sorted.map((product) => (
            <tr key={product.id} className="border-t">
              <td className="px-4 py-3 font-medium">{product.name}</td>
              <td className="px-4 py-3 text-right">${product.price.toFixed(2)}</td>
              <td className="px-4 py-3 text-right">{'"'‚ėÖ'.repeat(Math.round(product.rating))} {product.rating}</td>
              <td className=\"px-4 py-3 text-right\">{product.reviews.toLocaleString()}</td>
              <td className=\"px-4 py-3 text-center\">
                <span className={"'`px-2 py-1 rounded-full text-xs ${product.inStock ? '"'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}"'`}>
                  {product.inStock ? '"'In Stock' : 'Out of Stock'}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function computeStats(values: number[]) {
  const sorted = [...values].sort((a, b) => a - b);
  const n = sorted.length;
  const mean = values.reduce((s, v) => s + v, 0) / n;
  const median = n % 2 === 0 ? (sorted[n / 2 - 1] + sorted[n / 2]) / 2 : sorted[Math.floor(n / 2)];
  const variance = values.reduce((s, v) => s + (v - mean) ** 2, 0) / n;
  const std = Math.sqrt(variance);
  const q1 = sorted[Math.floor(n * 0.25)];
  const q3 = sorted[Math.floor(n * 0.75)];
  return { mean, median, std, variance, q1, q3 };
}

function AdvancedAnalysis({ products }: { products: Product[] }) {
  const prices = useMemo(() => products.map(p => p.price), [products]);
  const ratings = useMemo(() => products.map(p => p.rating), [products]);
  const reviews = useMemo(() => products.map(p => p.reviews), [products]);

  const priceStats = useMemo(() => computeStats(prices), [prices]);
  const ratingStats = useMemo(() => computeStats(ratings), [ratings]);
  const reviewStats = useMemo(() => computeStats(reviews), [reviews]);

  const sortedByValue = useMemo(() => {
    const valueScores = products.map(p => ({
      name: p.name,
      score: (p.rating / p.price) * 100,
